    { questionText: "Who invented the first synthetic purple dye, called mauveine, in 1856?", correctAnswer: "William Perkin", options: ["William Perkin", "John Herschel", "Max Miedinger", "Johannes Gutenberg"], explanation: "British chemist William Perkin invented the first synthetic purple dye, mauveine, in 1856.", hint: "This British chemist's invention finally made purple affordable to ordinary people." },
    { questionText: "What two primary colors are mixed to create purple?", correctAnswer: "Red and blue", options: ["Red and blue", "Yellow and blue", "Red and yellow", "Blue and green"], explanation: "Purple is created by mixing the primary colors red and blue.", hint: "Think about which two primary colors, when combined, are not yellow." },
    { questionText: "What United States military medal, established in 1932, uses purple to honor wounded service members?", correctAnswer: "The Purple Heart", options: ["The Purple Heart", "The Medal of Honor", "The Bronze Star", "The Silver Star"], explanation: "The Purple Heart, established in 1932, uses purple to honor wounded service members.", hint: "This medal's name directly includes the color purple." }
